export function buildInputField(field: DMMF.SchemaArg, context: GenerateContext): ts.Property {
  const tsType = buildAllFieldTypes(field.inputTypes, context)

  const tsProperty = ts.property(
    field.name, 
    field.isRequired ? tsType : appendSkipType(context, tsType)
  )

  if (!field.isRequired) {
    tsProperty.optional()
  }

  const docComment = ts.docComment()
  if (field.comment) {
    docComment.addText(field.comment)
  }
  if (field.deprecation) {
    docComment.addText(
      `@deprecated since ${field.deprecation.sinceVersion}: ${field.deprecation.reason}`
    )
  }

  if (docComment.lines.length > 0) {
    tsProperty.setDocComment(docComment)
  }

  return tsProperty
}
