import readline from 'node:readline'

import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import * as JsonRpc from './json-rpc'

export interface Handler {
  onGenerate(options: GeneratorOptions): Promise<any>
  onManifest?(config: GeneratorConfig): GeneratorManifest | Promise<GeneratorManifest>
}

export function generatorHandler(handler: Handler): void {
  const stdinInterface = readline.createInterface({
    input: process.stdin,
    crlfDelay: Infinity,
  })

  stdinInterface.on('line', async (line: string) => {
    const json = JSON.parse(line)

    if (json.method === 'generate' && json.params) {
      try {
        const result = await handler.onGenerate(json.params)
        respond({
          jsonrpc: '2.0',
          result: result,
          id: json.id,
        })
      } catch (_e) {
        const e = _e as Error
        respond({
          jsonrpc: '2.0',
          error: {
            code: -32000,
            message: e.message,
            data: {
              stack: e.stack,
            },
          },
          id: json.id,
        })
      }
    }

    if (json.method === 'getManifest') {
      if (handler.onManifest) {
        try {
          const manifest = await handler.onManifest(json.params)
          respond({
            jsonrpc: '2.0',
            result: {
              manifest,
            },
            id: json.id,
          })
        } catch (_e) {
          const e = _e as Error
          respond({
            jsonrpc: '2.0',
            error: {
              code: -32000,
              message: e.message,
              data: {
                stack: e.stack,
              },
            },
            id: json.id,
          })
        }
      } else {
        respond({
          jsonrpc: '2.0',
          result: {
            manifest: null,
          },
          id: json.id,
        })
      }
    }
  })

  process.stdin.resume()
}

function respond(response: JsonRpc.Response): void {
  process.stderr.write(JSON.stringify(response) + '\n')
}

import type * as DMMF from '@prisma/dmmf'

import { SqlQueryOutput } from './typedSql'

export interface GeneratorConfig {
  name: string
  output: EnvValue | null
  isCustomOutput?: boolean
  provider: EnvValue
  config: {
    /** `output` is a reserved name and will only be available directly at `generator.output` */
    output?: never
    /** `provider` is a reserved name and will only be available directly at `generator.provider` */
    provider?: never
    /** `binaryTargets` is a reserved name and will only be available directly at `generator.binaryTargets` */
    binaryTargets?: never
    /** `previewFeatures` is a reserved name and will only be available directly at `generator.previewFeatures` */
    previewFeatures?: never
  } & {
    [key: string]: string | string[] | undefined
  }
  binaryTargets: BinaryTargetsEnvValue[]
  // TODO why is this not optional?
  previewFeatures: string[]
  sourceFilePath: string
}

export interface EnvValue {
  fromEnvVar: null | string
  value: null | string
}

export interface BinaryTargetsEnvValue {
  fromEnvVar: string | null
  value: string
  native?: boolean
}

export type ConnectorType =
  | 'mysql'
  | 'mongodb'
  | 'sqlite'
  | 'postgresql'
  | 'postgres' // TODO: we could normalize postgres to postgresql this in engines to reduce the complexity?
  | 'prisma+postgres' // Note: used for Prisma Postgres, managed by PDP
  | 'sqlserver'
  | 'cockroachdb'

export type ActiveConnectorType = Exclude<ConnectorType, 'postgres' | 'prisma+postgres'>

export interface DataSource {
  name: string
  provider: ConnectorType
  // In Rust, this comes from `Connector::provider_name()`
  activeProvider: ActiveConnectorType
  schemas: string[] | []
  sourceFilePath: string
}

export type BinaryPaths = {
  schemaEngine?: { [binaryTarget: string]: string } // key: target, value: path
}

/** The options passed to the generator implementations */
export type GeneratorOptions = {
  generator: GeneratorConfig
  // TODO: what is otherGenerators for?
  otherGenerators: GeneratorConfig[]
  schemaPath: string
  dmmf: DMMF.Document
  datasources: DataSource[]
  // TODO deprecate datamodel & rename to schema?
  datamodel: string
  // TODO is it really always version hash? Feature is unclear.
  version: string // version hash
  binaryPaths?: BinaryPaths
  noHints?: boolean
  allowNoModels?: boolean
  typedSql?: SqlQueryOutput[]
}

export type EngineType = 'schemaEngine'

export type GeneratorManifest = {
  prettyName?: string
  defaultOutput?: string
  denylists?: {
    models?: string[]
    fields?: string[]
  }
  requiresGenerators?: string[]
  requiresEngines?: EngineType[]
  version?: string
  requiresEngineVersion?: string
}

import path from 'node:path'

import { BuildOptions } from './build'

type AdapterEntry = {
  entry: string
  outfile: string
}

export function createAdapterConfig(entries: AdapterEntry[]): BuildOptions[] {
  return entries.flatMap(({ entry, outfile }) => {
    const baseName = path.basename(outfile)

    return [
      {
        name: `${baseName}-cjs`,
        format: 'cjs' as const,
        bundle: true,
        entryPoints: [entry],
        outfile,
        outExtension: { '.js': '.js' },
        emitTypes: true,
      },
      {
        name: `${baseName}-esm`,
        format: 'esm' as const,
        bundle: true,
        entryPoints: [entry],
        outfile,
        outExtension: { '.js': '.mjs' },
        emitTypes: true,
      },
    ]
  })
}

export const adapterConfig = createAdapterConfig([{ entry: 'src/index.ts', outfile: 'dist/index' }])

export const unbundledConfig: BuildOptions[] = [
  {
    name: 'cjs',
    format: 'cjs',
    entryPoints: ['src/**/*.ts'],
    outdir: 'dist',
    outExtension: { '.js': '.js' },
    emitTypes: true,
  },
  {
    name: 'esm',
    format: 'esm',
    entryPoints: ['src/**/*.ts'],
    outdir: 'dist',
    outExtension: { '.js': '.mjs' },
    emitTypes: true,
  },
]

#!/usr/bin/env tsx

import path from 'node:path'

import { loadConfigFromFile } from '@prisma/config'
import Debug from '@prisma/debug'
import { enginesVersion } from '@prisma/engines-version'
import { arg, handlePanic, HelpError, isError } from '@prisma/internals'
import { bold, red } from 'kleur/colors'

import { version as packageVersion } from '../package.json'
import { CLI } from './CLI'
import { DbCommand } from './commands/DbCommand'
import { DbExecute } from './commands/DbExecute'
import { DbPull } from './commands/DbPull'
import { DbPush } from './commands/DbPush'
// import { DbDrop } from './commands/DbDrop'
import { DbSeed } from './commands/DbSeed'
import { MigrateCommand } from './commands/MigrateCommand'
import { MigrateDeploy } from './commands/MigrateDeploy'
import { MigrateDev } from './commands/MigrateDev'
import { MigrateDiff } from './commands/MigrateDiff'
import { MigrateReset } from './commands/MigrateReset'
import { MigrateResolve } from './commands/MigrateResolve'
import { MigrateStatus } from './commands/MigrateStatus'
import { getDatabaseVersionSafe } from './utils/getDatabaseVersionSafe'

process.on('uncaughtException', (e) => {
  console.log(e)
})
process.on('unhandledRejection', (e, promise) => {
  console.log(String(e), String(promise))
})
// Listen to Ctr + C and exit
process.once('SIGINT', () => {
  process.exit(130)
})

const commandArray = process.argv.slice(2)

const args = arg(
  commandArray,
  {
    '--config': String,
  },
  false,
  true,
)

/**
 * Main function
 */
async function main(): Promise<number> {
  // create a new CLI with our subcommands
  const cli = CLI.new({
    migrate: MigrateCommand.new({
      dev: MigrateDev.new(),
      status: MigrateStatus.new(),
      resolve: MigrateResolve.new(),
      reset: MigrateReset.new(),
      deploy: MigrateDeploy.new(),
      diff: MigrateDiff.new(),
    }),
    db: DbCommand.new({
      execute: DbExecute.new(),
      pull: DbPull.new(),
      push: DbPush.new(),
      // drop: DbDrop.new(),
      seed: DbSeed.new(),
    }),
  })

  const configFile = args['--config']
  const baseDir = configFile ? path.resolve(configFile, '..') : process.cwd()

  const { config, error } = await loadConfigFromFile({ configFile })
  if (error) {
    console.error(`Failed to load config file: ${error._tag}`)
    return 1
  }

  if (!config) {
    console.error('`prisma.config.ts` not found')
    return 1
  }

  try {
    // Execute the command
    const result = await cli.parse(commandArray, config, baseDir)
    // Did it error?
    if (result instanceof HelpError) {
      console.error(result)
      // TODO: We could do like Bash (and other)
      // = return an exit status of 2 to indicate incorrect usage like invalid options or missing arguments.
      // https://tldp.org/LDP/abs/html/exitcodes.html
      return 1
    } else if (isError(result)) {
      console.error(result)
      return 1
    }

    // Success
    console.log(result)
    return 0
  } catch (error) {
    if (error.rustStack) {
      await handlePanic({
        error,
        cliVersion: packageVersion,
        enginesVersion,
        command: commandArray.join(' '),
        getDatabaseVersionSafe: (args) => getDatabaseVersionSafe(args, config, baseDir),
      })
    }
    throw error
  }
}

/**
 * Run our program
 */
main()
  .then((code) => {
    if (code !== 0) {
      process.exit(code)
    }
  })
  .catch((error) => {
    if (Debug.enabled('migrate')) {
      console.error(red(bold('Error: ')) + error.stack)
    } else {
      console.error(red(bold('Error: ')) + error.message)
    }
    process.exit(1)
  })

import { ChokidarOptions, watch as createWatcher } from 'chokidar'
import * as esbuild from 'esbuild'
import { BuildContext } from 'esbuild'
import { writeFileSync } from 'fs'
import glob from 'globby'
import path from 'path'

import { debounce } from '../blaze/debounce'
import { flatten } from '../blaze/flatten'
import { handle } from '../blaze/handle'
import { map } from '../blaze/map'
import { omit } from '../blaze/omit'
import { pipe } from '../blaze/pipe'
import { transduce } from '../blaze/transduce'
import { fixImportsPlugin } from './plugins/fixImportsPlugin'
import { onErrorPlugin } from './plugins/onErrorPlugin'
import { resolvePathsPlugin } from './plugins/resolvePathsPlugin'
import { tscPlugin } from './plugins/tscPlugin'

export type BuildResult = esbuild.BuildResult
export type BuildOptions = esbuild.BuildOptions & {
  name?: string
  emitTypes?: boolean
  emitMetafile?: boolean
  outbase?: never // we don't support this
}

const DEFAULT_BUILD_OPTIONS = {
  platform: 'node',
  target: 'ES2022',
  logLevel: 'error',
  tsconfig: 'tsconfig.build.json',
  metafile: true,
} as const

/**
 * Apply defaults to the original build options
 * @param options the original build options
 */
const applyDefaults = (options: BuildOptions): BuildOptions => ({
  ...DEFAULT_BUILD_OPTIONS,
  format: 'cjs',
  outExtension: { '.js': '.js' },
  resolveExtensions: ['.ts', '.js', '.node'],
  entryPoints: glob.sync('./src/**/*.{j,t}s', {
    ignore: ['./src/__tests__/**/*'],
  }),
  mainFields: ['module', 'main'],
  ...options,
  // outfile has precedence over outdir, hence these ternaries
  outfile: options.outfile ? getOutFile(options) : undefined,
  outdir: options.outfile ? undefined : getOutDir(options),
  plugins: [
    ...(options.plugins ?? []),
    resolvePathsPlugin,
    fixImportsPlugin,
    tscPlugin(options.emitTypes),
    onErrorPlugin,
  ],
  external: [...(options.external ?? []), ...getProjectExternals(options)],
})

/**
 * Create two deferred builds for esm and cjs. The one follows the other:
 * - 1. The code gets compiled to an optimized tree-shaken esm output
 * - 2. We take that output and compile it to an optimized cjs output
 * @param options the original build options
 * @returns if options = [a, b], we get [a-esm, a-cjs, b-esm, b-cjs]
 */
function createBuildOptions(options: BuildOptions[]) {
  return flatten(
    map(options, (options) => [
      // we defer it so that we don't trigger glob immediately
      () => applyDefaults(options),
      // ... here can go more steps
    ]),
  )
}

/**
 * We only want to trigger the glob search once we are ready, and that is when
 * the previous build has finished. We get the build options from the deferred.
 */
function computeOptions(options: () => BuildOptions) {
  return options()
}

/**
 * Extensions are not automatically by esbuild set for `options.outfile`. We
 * look at the set `options.outExtension` and we add that to `options.outfile`.
 */
function addExtensionFormat(options: BuildOptions) {
  if (options.outfile && options.outExtension) {
    const ext = options.outExtension['.js']

    options.outfile = `${options.outfile}${ext}`
  }

  return options
}

/**
 * If we don't have `options.outfile`, we default `options.outdir`
 */
function addDefaultOutDir(options: BuildOptions) {
  if (options.outfile === undefined) {
    options.outdir = getOutDir(options)
  }

  return options
}

/**
 * Execute esbuild with all the configurations we pass
 */
async function executeEsBuild(options: BuildOptions) {
  if (process.env.WATCH === 'true') {
    const context = await esbuild.context(omit(options, ['name', 'emitTypes', 'emitMetafile']) as any)

    watch(context, options)
  }

  const build = await esbuild.build(omit(options, ['name', 'emitTypes', 'emitMetafile']) as any)
  const outdir = options.outdir ?? (options.outfile ? path.dirname(options.outfile) : undefined)

  if (build.metafile && options.emitMetafile) {
    const metafilePath = `${outdir}/${options.name}.meta.json`
    writeFileSync(metafilePath, JSON.stringify(build.metafile))
  }

  return [options, build] as const
}

/**
 * Execution pipeline that applies a set of actions
 * @param options
 */
export async function build(options: BuildOptions[]) {
  return transduce.async(
    createBuildOptions(options),
    pipe.async(computeOptions, logStartBuild, addExtensionFormat, addDefaultOutDir, executeEsBuild),
  )
}

/**
 * Prints a message every time a new bundle is built
 */
function logStartBuild(options: BuildOptions): BuildOptions {
  console.log(`Building ${options.name} as ${options.format ?? 'cjs'}...`)
  return options
}

/**
 * Executes the build and rebuilds what is necessary
 * @param builds
 */
const watch = (context: BuildContext, options: BuildOptions) => {
  if (process.env.WATCH !== 'true') return context

  // common chokidar options for the watchers
  const config = {
    ignoreInitial: true,
    ignored: [/$src\/__tests__\//, 'package.json'],
  } satisfies ChokidarOptions

  // prepare the incremental builds watcher
  const changeWatcher = createWatcher(['./src'], config)

  // triggers quick rebuild on file change
  const fastRebuild = debounce(async () => {
    const timeBefore = Date.now()

    // we handle possible rebuild exceptions
    const rebuildResult = await handle.async(() => {
      return context.rebuild()
    })

    // Handle unexpected internal errors
    if (rebuildResult instanceof Error) {
      console.error(rebuildResult)
      // Handle build errors (e.g., syntax errors)
    } else if (rebuildResult.errors.length > 0) {
      // Log the detailed error object from esbuild for better debugging.
      console.error(rebuildResult.errors)
    }

    console.log(`${Date.now() - timeBefore}ms [${options.name ?? ''}]`)
  }, 10)

  changeWatcher.on('change', fastRebuild)

  return undefined
}

// Utils ::::::::::::::::::::::::::::::::::::::::::::::::::

// get a default directory if needed (no outfile)
function getOutDir(options: BuildOptions) {
  if (options.outfile !== undefined) {
    return path.dirname(options.outfile)
  }

  return options.outdir ?? 'dist'
}

// get the output file from an original path
function getOutFile(options: BuildOptions) {
  if (options.outfile !== undefined) {
    const dirname = getOutDir(options)
    const filename = path.basename(options.outfile)

    return `${dirname}/${filename}`
  }

  return undefined
}

// get the current project externals this helps to mark dependencies as external
// by having convention in the package.json (dev = bundled, non-dev = external)
function getProjectExternals(options: BuildOptions) {
  const pkg = require(`${process.cwd()}/package.json`)
  const peerDeps = Object.keys(pkg.peerDependencies ?? {})
  const regDeps = Object.keys(pkg.dependencies ?? {})

  // when bundling, only the devDeps will be bundled
  if (!process.env.IGNORE_EXTERNALS && options.bundle === true) {
    return [...new Set([...peerDeps, ...regDeps])]
  }

  // otherwise, all the dependencies will be bundled
  return []
}

