import type * as DMMF from '@prisma/dmmf'

import { scalarToTs } from './scalar-types'

/**
 * Returns the TypeScript type expression for a non-relation DMMF field, taking
 * into account list cardinality.
 */
function fieldTypeExpr(field: DMMF.Field): string {
  let base: string
  if (field.kind === 'enum') {
    base = field.type
  } else {
    base = scalarToTs(field.type)
  }
  return field.isList ? `${base}[]` : base
}

/**
 * Generates the TypeScript interface for a model, including only scalar and
 * enum fields.  Relation fields are excluded because REST APIs return flat
 * objects.
 */
function buildModelInterface(model: DMMF.Model): string {
  const fields = model.fields.filter((f) => f.kind !== 'object')
  const lines = fields.map((f) => {
    const typeExpr = fieldTypeExpr(f)
    const opt = f.isRequired ? '' : '?'
    const nullable = !f.isRequired && !f.isList ? ' | null' : ''
    return `  ${f.name}${opt}: ${typeExpr}${nullable}`
  })
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/** Generates an enum declaration from a DMMF enum definition. */
function buildEnum(e: DMMF.DatamodelEnum): string {
  const values = e.values.map((v) => `  ${v.name} = '${v.name}'`).join(',\n')
  return `export enum ${e.name} {\n${values}\n}`
}

/**
 * Generates a `WhereUniqueInput` type as a discriminated union, with one
 * variant per `@id` or `@unique` field.
 */
function buildWhereUniqueInput(model: DMMF.Model): string {
  const uniqueFields = model.fields.filter((f) => f.kind === 'scalar' && (f.isId || f.isUnique))
  if (uniqueFields.length === 0) {
    return `export type ${model.name}WhereUniqueInput = Record<string, never>`
  }
  const variants = uniqueFields.map((f) => `{ ${f.name}: ${scalarToTs(f.type)} }`)
  return `export type ${model.name}WhereUniqueInput =\n  | ${variants.join('\n  | ')}`
}

/**
 * Generates a `CreateInput` interface.  Fields that are required, have no
 * default value, and are not auto-generated are mandatory; all others are
 * optional.
 */
function buildCreateInput(model: DMMF.Model): string {
  const fields = model.fields.filter((f) => f.kind !== 'object')
  const lines = fields.map((f) => {
    const typeExpr = fieldTypeExpr(f)
    const nullable = !f.isRequired && !f.isList ? ' | null' : ''
    const required = f.isRequired && !f.hasDefaultValue && !f.isGenerated
    const opt = required ? '' : '?'
    return `  ${f.name}${opt}: ${typeExpr}${nullable}`
  })
  return `export interface ${model.name}CreateInput {\n${lines.join('\n')}\n}`
}

/**
 * Generates an `UpdateInput` interface with all fields optional, suitable for
 * partial-update (PATCH) semantics.
 */
function buildUpdateInput(model: DMMF.Model): string {
  const fields = model.fields.filter((f) => f.kind !== 'object')
  const lines = fields.map((f) => {
    const typeExpr = fieldTypeExpr(f)
    const nullable = !f.isRequired && !f.isList ? ' | null' : ''
    return `  ${f.name}?: ${typeExpr}${nullable}`
  })
  return `export interface ${model.name}UpdateInput {\n${lines.join('\n')}\n}`
}

/** Generates the full `types.ts` file content from the DMMF document. */
export function generateTypes(dmmf: DMMF.Document): string {
  const parts: string[] = []

  for (const e of dmmf.datamodel.enums) {
    parts.push(buildEnum(e))
  }

  for (const model of dmmf.datamodel.models) {
    parts.push(buildModelInterface(model))
    parts.push(buildWhereUniqueInput(model))
    parts.push(buildCreateInput(model))
    parts.push(buildUpdateInput(model))
  }

  return parts.join('\n\n') + '\n'
}

