import type * as DMMF from '@prisma/dmmf'

/** Lowercases the first character of a string. */
function lcFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/**
 * Generates a per-model client class with CRUD methods that call a REST
 * endpoint.  The generated class is designed to be embedded in `client.ts`
 * which imports its type parameters from `./types`.
 */
function buildModelClient(model: DMMF.Model): string {
  const T = model.name
  const path = `${lcFirst(T)}s`

  return `export class ${T}Client {
  #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl
  }

  async findMany(params?: Record<string, string>): Promise<${T}[]> {
    const query = params ? '?' + new URLSearchParams(params).toString() : ''
    const res = await fetch(\`\${this.#baseUrl}/${path}\${query}\`)
    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)
    return res.json() as Promise<${T}[]>
  }

  async findUnique(where: ${T}WhereUniqueInput): Promise<${T} | null> {
    const key = Object.keys(where)[0] as string
    const value = (where as Record<string, unknown>)[key]
    const res = await fetch(\`\${this.#baseUrl}/${path}/\${encodeURIComponent(String(value))}\`)
    if (res.status === 404) return null
    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)
    return res.json() as Promise<${T}>
  }

  async create(data: ${T}CreateInput): Promise<${T}> {
    const res = await fetch(\`\${this.#baseUrl}/${path}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)
    return res.json() as Promise<${T}>
  }

  async update(where: ${T}WhereUniqueInput, data: ${T}UpdateInput): Promise<${T}> {
    const key = Object.keys(where)[0] as string
    const value = (where as Record<string, unknown>)[key]
    const res = await fetch(\`\${this.#baseUrl}/${path}/\${encodeURIComponent(String(value))}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)
    return res.json() as Promise<${T}>
  }

  async delete(where: ${T}WhereUniqueInput): Promise<${T}> {
    const key = Object.keys(where)[0] as string
    const value = (where as Record<string, unknown>)[key]
    const res = await fetch(\`\${this.#baseUrl}/${path}/\${encodeURIComponent(String(value))}\`, {
      method: 'DELETE',
    })
    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)
    return res.json() as Promise<${T}>
  }
}`
}

/** Generates the full `client.ts` file content from the DMMF document. */
export function generateClient(dmmf: DMMF.Document): string {
  const models = dmmf.datamodel.models

  const typeImports = models
    .flatMap((m) => [
      m.name,
      `${m.name}WhereUniqueInput`,
      `${m.name}CreateInput`,
      `${m.name}UpdateInput`,
    ])
    .join(', ')

  const importLine = `import type { ${typeImports} } from './types'`

  const modelClients = models.map(buildModelClient)

  const restClientProps = models
    .map((m) => `  readonly ${lcFirst(m.name)}: ${m.name}Client`)
    .join('\n')

  const restClientAssignments = models
    .map((m) => `    this.${lcFirst(m.name)} = new ${m.name}Client(baseUrl)`)
    .join('\n')

  const restClient = `export class RestClient {
${restClientProps}

  constructor(baseUrl: string) {
${restClientAssignments}
  }
}`

  return [importLine, ...modelClients, restClient].join('\n\n') + '\n'
}

