import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { generateClient } from './generate-client'
import { generateIndex } from './generate-index'
import { generateTypes } from './generate-types'

/** Maps output file names to their generated text content. */
export type FileMap = Record<string, string>

/** Builds the in-memory map of files to generate, without writing to disk. */
export function buildFileMap(dmmf: DMMF.Document): FileMap {
  return {
    'types.ts': generateTypes(dmmf),
    'client.ts': generateClient(dmmf),
    'index.ts': generateIndex(dmmf),
  }
}

/** Writes all files in a `FileMap` to the given output directory. */
export async function writeFileMap(outputDir: string, files: FileMap): Promise<void> {
  await fs.mkdir(outputDir, { recursive: true })
  await Promise.all(
    Object.entries(files).map(([name, content]) => fs.writeFile(path.join(outputDir, name), content, 'utf-8')),
  )
}

/** Orchestrates code generation: builds file content and writes to disk. */
export async function generate(dmmf: DMMF.Document, outputDir: string): Promise<void> {
  const files = buildFileMap(dmmf)
  await writeFileMap(outputDir, files)
}

